// WebGPU compat test #3: full render path — shader → pipeline → render pass →
// offscreen texture → copyTextureToBuffer → staging readback. Renders a red
// triangle on a black clear into a 64x64 rgba8unorm texture and samples the
// center (inside → red) and a corner (outside → clear black). Oracle (Deno) and
// monster must agree pixel-for-pixel.
const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();
const W = 64, H = 64;
const tex = device.createTexture({
  size: { width: W, height: H },
  format: 'rgba8unorm',
  usage: GPUTextureUsage.RENDER_ATTACHMENT | GPUTextureUsage.COPY_SRC,
});
const shader = device.createShaderModule({
  code: `
    @vertex fn vs(@builtin(vertex_index) i: u32) -> @builtin(position) vec4f {
      var p = array<vec2f,3>(vec2f(0.0, 0.7), vec2f(-0.7, -0.7), vec2f(0.7, -0.7));
      return vec4f(p[i], 0.0, 1.0);
    }
    @fragment fn fs() -> @location(0) vec4f { return vec4f(1.0, 0.0, 0.0, 1.0); }
  `,
});
const pipeline = device.createRenderPipeline({
  layout: 'auto',
  vertex: { module: shader, entryPoint: 'vs' },
  fragment: { module: shader, entryPoint: 'fs', targets: [{ format: 'rgba8unorm' }] },
  primitive: { topology: 'triangle-list' },
});
const enc = device.createCommandEncoder();
const pass = enc.beginRenderPass({
  colorAttachments: [{
    view: tex.createView(),
    loadOp: 'clear',
    storeOp: 'store',
    clearValue: { r: 0, g: 0, b: 0, a: 1 },
  }],
});
pass.setPipeline(pipeline);
pass.draw(3);
pass.end();

const bytesPerRow = W * 4; // 256, already 256-aligned
const readBuf = device.createBuffer({
  size: bytesPerRow * H,
  usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ,
});
enc.copyTextureToBuffer(
  { texture: tex },
  { buffer: readBuf, bytesPerRow },
  { width: W, height: H }
);
device.queue.submit([enc.finish()]);
await readBuf.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(readBuf.getMappedRange());
const at = (x, y) => { const o = y * bytesPerRow + x * 4; return [px[o], px[o + 1], px[o + 2], px[o + 3]]; };
out.center = at(32, 40);  // inside the triangle → red
out.corner = at(2, 2);    // outside → clear black
readBuf.unmap();
console.log('__RESULT__ ' + JSON.stringify(out));
